DELIMITER $$
--
-- Procedures
--
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_finalize_session_attendance` (IN `p_session_id` INT, IN `p_user_id` INT)   BEGIN
    DECLARE v_duration INT;
    DECLARE v_late_threshold INT;
    DECLARE v_min_presence_percent DECIMAL(3,2);
    DECLARE v_camera_downtime INT;
    DECLARE v_adjusted_duration INT;
    DECLARE v_required_presence INT;
    
    -- Get session parameters
    SELECT 
        duration_seconds, 
        late_threshold_seconds, 
        min_presence_percent,
        IFNULL(camera_downtime_seconds, 0)
    INTO 
        v_duration, 
        v_late_threshold, 
        v_min_presence_percent,
        v_camera_downtime
    FROM attendance_sessions
    WHERE id = p_session_id;
    
    -- Calculate adjusted requirements
    SET v_adjusted_duration = v_duration - v_camera_downtime;
    SET v_required_presence = FLOOR(v_adjusted_duration * v_min_presence_percent);
    
    -- Process detected students (aggregate detection events)
    INSERT INTO attendance (
        session_id, rollnumber, student_name, date, 
        status, marked_by_system, 
        first_detected_at, last_detected_at, 
        total_presence_seconds, detection_count, 
        presence_percentage, confidence_score, notes
    )
    SELECT 
        p_session_id,
        de.rollnumber,
        s.name,
        CURDATE(),
        CASE
            -- Determine status based on arrival time and total presence
            WHEN MIN(de.detected_at_seconds) <= v_late_threshold THEN
                -- Arrived on time
                CASE 
                    WHEN COUNT(*) >= v_required_presence THEN 'present'
                    WHEN COUNT(*) >= v_adjusted_duration * 0.50 THEN 'early_departure'
                    ELSE 'insufficient'
                END
            ELSE
                -- Arrived late
                CASE 
                    WHEN COUNT(*) >= v_required_presence THEN 'late'
                    WHEN COUNT(*) >= v_adjusted_duration * 0.50 THEN 'early_departure'
                    ELSE 'insufficient'
                END
        END as status,
        1, -- marked_by_system
        MIN(de.detected_at_seconds) as first_detected_at,
        MAX(de.detected_at_seconds) as last_detected_at,
        COUNT(*) as total_presence_seconds,
        COUNT(*) as detection_count,
        ROUND((COUNT(*) * 100.0) / v_adjusted_duration, 2) as presence_percentage,
        AVG(de.confidence_score) as avg_confidence,
        CONCAT(
            'Detected: ', COUNT(*), 's / ', v_adjusted_duration, 's required (', 
            ROUND((COUNT(*) * 100.0) / v_adjusted_duration, 1), '%)'
        ) as notes
    FROM detection_events de
    JOIN students s ON de.rollnumber = s.rollnumber
    WHERE de.session_id = p_session_id
    GROUP BY de.rollnumber, s.name;
    
    -- Mark undetected students as absent
    INSERT INTO attendance (
        session_id, rollnumber, student_name, date, 
        status, marked_by_system, modified_by, notes,
        first_detected_at, total_presence_seconds, presence_percentage
    )
    SELECT 
        p_session_id,
        s.rollnumber,
        s.name,
        CURDATE(),
        'absent',
        0,
        p_user_id,
        'Never detected during session',
        NULL,
        0,
        0.00
    FROM class_students cs
    JOIN students s ON cs.rollnumber = s.rollnumber
    JOIN attendance_sessions asess ON cs.class_id = asess.class_id
    WHERE asess.id = p_session_id
    AND s.rollnumber NOT IN (
        SELECT rollnumber FROM attendance WHERE session_id = p_session_id
    )
    AND s.is_active = 1;
    
    -- Delete processed detection events (save space)
    DELETE FROM detection_events WHERE session_id = p_session_id;
    
    -- Update session status
    UPDATE attendance_sessions
    SET status = 'completed',
        actual_end_time = NOW()
    WHERE id = p_session_id;
    
    -- Return summary
    SELECT 
        COUNT(CASE WHEN status = 'present' THEN 1 END) as total_present,
        COUNT(CASE WHEN status = 'late' THEN 1 END) as total_late,
        COUNT(CASE WHEN status = 'absent' THEN 1 END) as total_absent,
        COUNT(CASE WHEN status = 'early_departure' THEN 1 END) as total_early_departure,
        COUNT(CASE WHEN status = 'insufficient' THEN 1 END) as total_insufficient,
        COUNT(*) as total_students
    FROM attendance
    WHERE session_id = p_session_id;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_get_unmarked_students` (IN `p_session_id` INT)   BEGIN
    SELECT 
        s.rollnumber,
        s.name,
        s.phone,
        s.email
    FROM class_students cs
    JOIN students s ON cs.rollnumber = s.rollnumber
    JOIN attendance_sessions asess ON cs.class_id = asess.class_id
    WHERE asess.id = p_session_id
    AND s.rollnumber NOT IN (
        SELECT rollnumber 
        FROM attendance 
        WHERE session_id = p_session_id
    )
    AND s.is_active = 1
    ORDER BY s.name;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_mark_attendance` (IN `p_session_id` INT, IN `p_rollnumber` VARCHAR(50), IN `p_student_name` VARCHAR(100), IN `p_confidence` DECIMAL(4,3))   BEGIN
    DECLARE v_exists INT;
    
    -- Check if already marked
    SELECT COUNT(*) INTO v_exists
    FROM attendance
    WHERE session_id = p_session_id 
    AND rollnumber = p_rollnumber;
    
    IF v_exists = 0 THEN
        INSERT INTO attendance (
            session_id, rollnumber, student_name, 
            confidence_score, date, status, marked_by_system
        ) VALUES (
            p_session_id, p_rollnumber, p_student_name, 
            p_confidence, CURDATE(), 'present', 1
        );
        
        SELECT 'SUCCESS' as result, LAST_INSERT_ID() as attendance_id;
    ELSE
        SELECT 'DUPLICATE' as result, 0 as attendance_id;
    END IF;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_mark_remaining_absent` (IN `p_session_id` INT, IN `p_user_id` INT)   BEGIN
    -- Mark students who were NEVER detected as absent
    INSERT INTO attendance (
        session_id, rollnumber, student_name, date, 
        status, marked_by_system, modified_by, notes,
        first_detected_at, total_presence_seconds, presence_percentage
    )
    SELECT 
        p_session_id,
        s.rollnumber,
        s.name,
        CURDATE(),
        'absent',
        0,
        p_user_id,
        'Never detected during session',
        NULL,
        0,
        0.00
    FROM class_students cs
    JOIN students s ON cs.rollnumber = s.rollnumber
    JOIN attendance_sessions asess ON cs.class_id = asess.class_id
    WHERE asess.id = p_session_id
    AND s.rollnumber NOT IN (
        SELECT rollnumber FROM attendance WHERE session_id = p_session_id
    )
    AND s.is_active = 1;
    
    SELECT ROW_COUNT() as students_marked;
END$$

