--
-- Table structure for table `attendance`
--

CREATE TABLE `attendance` (
  `id` int(11) NOT NULL,
  `session_id` int(11) DEFAULT NULL,
  `rollnumber` varchar(50) NOT NULL,
  `student_name` varchar(100) DEFAULT NULL,
  `confidence_score` decimal(4,3) DEFAULT NULL,
  `first_detected_at` int(11) DEFAULT NULL COMMENT 'Seconds from session start when first detected',
  `last_detected_at` int(11) DEFAULT NULL COMMENT 'Seconds from session start when last detected',
  `total_presence_seconds` int(11) DEFAULT 0 COMMENT 'Cumulative seconds face detected (includes gaps)',
  `detection_count` int(11) DEFAULT 0 COMMENT 'Number of detection events logged',
  `presence_percentage` decimal(5,2) DEFAULT NULL COMMENT 'Calculated presence as % of (duration - downtime)',
  `status` enum('present','late','absent','excused','early_departure','insufficient') DEFAULT 'absent' COMMENT 'present=on-time+80%+, late=late+80%+, insufficient=<80%, early_departure=left early, absent=never detected',
  `timestamp` datetime DEFAULT current_timestamp(),
  `date` date DEFAULT NULL,
  `notes` text DEFAULT NULL,
  `marked_by_system` tinyint(1) DEFAULT 1,
  `manually_modified` tinyint(1) DEFAULT 0,
  `modified_by` int(11) DEFAULT NULL,
  `modified_at` timestamp NULL DEFAULT NULL,
  `modification_reason` text DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

