DELIMITER $$
CREATE TRIGGER `tr_set_attendance_date` BEFORE INSERT ON `attendance` FOR EACH ROW BEGIN
    IF NEW.date IS NULL THEN
        SET NEW.date = DATE(NEW.timestamp);
    END IF;
END
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `tr_update_session_stats_insert` AFTER INSERT ON `attendance` FOR EACH ROW BEGIN
    IF NEW.session_id IS NOT NULL THEN
        UPDATE attendance_sessions
        SET 
            total_present = (
                SELECT COUNT(*) 
                FROM attendance 
                WHERE session_id = NEW.session_id 
                AND status IN ('present','late')
            ),
            total_absent = (
                SELECT COUNT(*) 
                FROM attendance 
                WHERE session_id = NEW.session_id 
                AND status = 'absent'
            )
        WHERE id = NEW.session_id;
    END IF;
END
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `tr_update_session_stats_update` AFTER UPDATE ON `attendance` FOR EACH ROW BEGIN
